import { changeVersionPrefix } from "./changeVersionPrefix.js";
import { getDependencyVersionFromFindUpPackageJson } from "./getDependencyVersionFromFindUpPackageJson.js";

/**
 * Resolves dependencies to their versions per our package.json if undefined.
 * Sets the prefix to `^` for the version specified or read from package.json.
 * @param deps
 * @returns
 */
export async function resolveDependenciesFromFindUp(
  deps: { [key: string]: string | undefined },
  cwd: string,
): Promise<{
  dependencyName: string;
  dependencyVersion: string;
}[]> {
  return await Promise.all(
    Object.entries(deps).map(
      async ([dependencyName, dependencyVersion]) => {
        return {
          dependencyName,
          dependencyVersion: changeVersionPrefix(
            dependencyVersion
              ?? await getDependencyVersionFromFindUpPackageJson(
                dependencyName,
                {
                  cwd,
                },
              ),
            "^",
          ),
        };
      },
    ),
  );
}
